"use client";

import { useState, useEffect } from "react";
import { doc, getDoc } from "firebase/firestore";
import { db } from "../../../firebase"; // make sure this path points to your firebase config

export default function ScanPage({ params }) {
  const qr_id = params.qr_id;
  const [vehicle, setVehicle] = useState(null);
  const [loading, setLoading] = useState(true);

  // Fetch vehicle details from Firestore
  useEffect(() => {
    const fetchVehicle = async () => {
      try {
        // Assumes your vehicle document ID is qr_id
        const vehicleSnap = await getDoc(doc(db, "vehicles", qr_id));
        if (vehicleSnap.exists()) {
          setVehicle(vehicleSnap.data());
        } else {
          setVehicle(null);
        }
      } catch (error) {
        console.error("Error fetching vehicle:", error);
        setVehicle(null);
      }
      setLoading(false);
    };

    fetchVehicle();
  }, [qr_id]);

  // Single email button
  const handleEmail = () => {
    const subject = "DriveAlert QR Notification";
    const body = `Hello,

Your vehicle (${vehicle.plate_number}) has been scanned via DriveAlert QR.

Reason: [Describe the issue]

Regards,
DriveAlert User`;

    window.location.href = `mailto:${vehicle.owner_email}?subject=${encodeURIComponent(
      subject
    )}&body=${encodeURIComponent(body)}`;
  };

  // Multiple pre-written email messages
  const sendPresetEmail = (message) => {
    const subject = "DriveAlert QR Alert";
    const body = `Hello,

${message}

Vehicle: ${vehicle.plate_number}

Regards,
DriveAlert User`;

    window.location.href = `mailto:${vehicle.owner_email}?subject=${encodeURIComponent(
      subject
    )}&body=${encodeURIComponent(body)}`;
  };

  if (loading) return <p>Loading...</p>;
  if (!vehicle) return <p>QR not registered yet.</p>;

  return (
    <div style={{ padding: "20px", fontFamily: "Arial, sans-serif" }}>
      <h2>Vehicle Details</h2>
      <p><strong>Plate Number:</strong> {vehicle.plate_number}</p>
      <p><strong>Make:</strong> {vehicle.make}</p>
      <p><strong>Model:</strong> {vehicle.model}</p>

      <h3>Contact Owner</h3>
      <button
        onClick={handleEmail}
        style={{ marginBottom: "10px", padding: "10px", cursor: "pointer" }}
      >
        Send Email
      </button>

      <h4>Quick Notifications</h4>
      <button
        onClick={() => sendPresetEmail("Your car lights are on.")}
        style={{ marginRight: "10px", padding: "10px", cursor: "pointer" }}
      >
        Lights On
      </button>
      <button
        onClick={() => sendPresetEmail("Your car is blocking access.")}
        style={{ marginRight: "10px", padding: "10px", cursor: "pointer" }}
      >
        Blocking Access
      </button>
      <button
        onClick={() => sendPresetEmail("Your alarm is going off.")}
        style={{ padding: "10px", cursor: "pointer" }}
      >
        Alarm Triggered
      </button>
    </div>
  );
}